def findRepeatedDnaSequences(self, s: str) -> List[str]:
    count_dict = {}
    for c in s:
        count_dict[c] = count_dict.get(c, 0) + 1
    result = []
    for c in s:
        if count_dict[c] > 1:
            result.append(c)
    return result

